//! Recursive accountability — delegation must ATTENUATE.
//!
//! A parent agent can spawn a CHILD, but only within its own authority. Spawn
//! authority is delegated DOWN the tree, attenuated to a caps subset, and the
//! delegation is crypto-proven (a UCAN chain root -> parent -> child that
//! `verify_chain` accepts). No privilege escalation down the tree.
//!
//! Covered here, end to end through `ops::delegate_spawn` + `ops::spawn` (with a
//! fake monster-guard so no real runtime is needed):
//!   1. `delegate-spawn` produces a chain `verify_chain` accepts with attenuated
//!      caps (root -> parent holder -> child DID, leaf caps = the subset).
//!   2. A spawn whose `--caps` are WITHIN the delegated subset is ADMITTED, and
//!      its ledger row records the delegation depth (the chain length).
//!   3. A spawn whose `--caps` EXCEED the delegated subset is DENIED with the
//!      caps-subset error.
//!   4. A non-attenuating delegate (subset > parent) is rejected by a0n-auth.
//!   5. An unrestricted root-issued spawn keeps today's behavior (any caps).
//!
//! Each test owns a per-name temp `$MONSTER_GUARD_HOME`; they share the global
//! env so a mutex serializes them.

use std::os::unix::fs::PermissionsExt;
use std::path::PathBuf;
use std::sync::Mutex;

use a0n_auth::ucan::issue;
use a0n_auth::{verify_chain, Capability, IssueOptions, Keypair};

use monster_swarm::budget::Caste;
use monster_swarm::ops::{self, DelegateSpawnRequest, SpawnRequest, DEFAULT_GRANT_TTL_SECS};
use monster_swarm::store;

static ENV_GUARD: Mutex<()> = Mutex::new(());

/// Fake `monster-guard`: delegate + revoke exit 0; run stays alive briefly so the
/// supervisor pid is live when the ledger is saved.
fn fake_guard(dir: &PathBuf) -> PathBuf {
    let bin = dir.join("monster-guard");
    let script = "#!/bin/sh\n\
         if [ \"$1\" = \"run\" ]; then\n\
         \texec sleep 30\n\
         fi\n\
         exit 0\n";
    std::fs::write(&bin, script).unwrap();
    std::fs::set_permissions(&bin, std::fs::Permissions::from_mode(0o755)).unwrap();
    bin
}

fn fake_node(dir: &PathBuf) -> PathBuf {
    let node = dir.join("fake-node");
    std::fs::write(&node, "#!/bin/sh\nexit 0\n").unwrap();
    std::fs::set_permissions(&node, std::fs::Permissions::from_mode(0o755)).unwrap();
    node
}

struct Home {
    path: PathBuf,
}

impl Home {
    fn new(name: &str) -> Home {
        let path = std::env::temp_dir().join(format!("monster-swarm-{name}-{}", std::process::id()));
        let _ = std::fs::remove_dir_all(&path);
        std::fs::create_dir_all(&path).unwrap();
        std::env::set_var("MONSTER_GUARD_HOME", &path);
        let bindir = path.join("bin");
        std::fs::create_dir_all(&bindir).unwrap();
        std::env::set_var("MONSTER_GUARD_BIN", fake_guard(&bindir));
        fake_node(&bindir);
        std::env::set_var("MONSTER_SWARM_NODES", &bindir);
        Home { path }
    }
}

impl Drop for Home {
    fn drop(&mut self) {
        std::env::remove_var("MONSTER_GUARD_HOME");
        std::env::remove_var("MONSTER_GUARD_BIN");
        std::env::remove_var("MONSTER_SWARM_NODES");
        let _ = std::fs::remove_dir_all(&self.path);
    }
}

/// A root-issued capability granting agent/spawn on the fleet, addressed to the
/// `to` DID, with optional `constraints.caps`. With `caps == None` it is
/// unrestricted (a root holder spawns directly, today's behavior).
fn root_spawn_ucan(to: &str, caps: Option<&[&str]>) -> String {
    let root = store::ensure_root().expect("root");
    let constraints = caps.map(|c| {
        let arr: Vec<&str> = c.to_vec();
        serde_json::json!({ "caps": arr })
    });
    let cap = Capability {
        can: "agent/spawn".into(),
        with: "agent:fleet".into(),
        constraints,
    };
    issue(&root, to, &[cap], 3600, &IssueOptions::default()).expect("root ucan")
}

fn spawn_req(ucan: &str, id: &str, caps: &[&str]) -> SpawnRequest {
    SpawnRequest {
        ucan: ucan.to_string(),
        node: "fake-node".into(),
        id: Some(id.to_string()),
        caste: Caste::Scout,
        caps: caps.iter().map(|s| s.to_string()).collect(),
        lease_secs: 60,
        max_secs: None,
        grant_ttl_secs: DEFAULT_GRANT_TTL_SECS,
        node_args: vec![],
        qspec: None,
        oath: None,
        teleport: None,
    }
}

#[test]
fn delegate_spawn_produces_an_attenuated_chain_verify_chain_accepts() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("delspawn-chain");

    let parent = Keypair::generate();
    let child = Keypair::generate();
    let root = store::ensure_root().expect("root");

    // root -> parent holder (unrestricted agent/spawn).
    let parent_token = root_spawn_ucan(parent.did(), None);

    // The parent delegates DOWN, attenuated to caps=[net].
    let out = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: parent_token,
        issuer_secret_hex: parent.secret_hex(),
        to_did: child.did().to_string(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("attenuated delegation");
    assert_eq!(out.to_did, child.did());
    assert_eq!(out.caps, vec!["net".to_string()]);

    // The child token verifies as a depth-2 chain rooted at the resident root,
    // addressed to the child, carrying the attenuated caps subset.
    let res = verify_chain(&out.token, None, None);
    assert!(res.valid, "delegated chain must verify: {:?}", res.error);
    assert_eq!(res.chain.len(), 2, "root -> parent -> child");
    assert_eq!(res.root_issuer.as_deref(), Some(root.did()));
    let leaf = res.chain.first().expect("leaf");
    assert_eq!(leaf.aud, child.did());
    let caps = leaf.att[0].constraints.as_ref().expect("constraints")["caps"]
        .as_array()
        .expect("caps array");
    assert_eq!(caps.len(), 1);
    assert_eq!(caps[0], "net");
}

#[test]
fn spawn_within_the_delegated_subset_is_admitted_and_records_depth() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("delspawn-within");

    let parent = Keypair::generate();
    let child = Keypair::generate();

    // root -> parent (agent/spawn caps=[net,fs]); parent -> child caps=[net].
    let parent_token = root_spawn_ucan(parent.did(), Some(&["net", "fs"]));
    let child_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: parent_token,
        issuer_secret_hex: parent.secret_hex(),
        to_did: child.did().to_string(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate")
    .token;

    // The child spawns within its delegated subset (caps=[net]) — ADMITTED.
    ops::spawn(spawn_req(&child_token, "kid", &["net"]))
        .expect("spawn within the delegated subset is admitted");
    let rec = store::load_fleet().find("kid").expect("ledger").clone();
    assert_eq!(rec.caps, vec!["net".to_string()]);
    // Lineage: depth 2 (root -> parent -> child), recorded on the ledger.
    assert_eq!(rec.depth, 2, "the delegation depth is recorded on the spawn");

    // The Thoth fleet frame surfaces the depth so the tree is visible.
    let oaths = store::load_fleet().oaths();
    assert_eq!(oaths[0].depth, 2, "depth is surfaced for the frame");
}

#[test]
fn spawn_exceeding_the_delegated_subset_is_denied() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("delspawn-exceed");

    let parent = Keypair::generate();
    let child = Keypair::generate();

    // root -> parent (caps=[net,fs]); parent -> child caps=[net].
    let parent_token = root_spawn_ucan(parent.did(), Some(&["net", "fs"]));
    let child_token = ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: parent_token,
        issuer_secret_hex: parent.secret_hex(),
        to_did: child.did().to_string(),
        caps: vec!["net".into()],
        ttl_secs: 1800,
    })
    .expect("delegate")
    .token;

    // The child tries to spawn with fs — OUTSIDE its delegated [net] — DENIED.
    let err = match ops::spawn(spawn_req(&child_token, "overreach", &["net", "fs"])) {
        Ok(_) => panic!("a spawn exceeding the delegated caps must be denied"),
        Err(e) => e,
    };
    assert!(err.contains("spawn denied"), "caps-subset denial: {err}");
    assert!(err.contains("exceed the delegated caps"), "names the cause: {err}");
    assert!(err.contains("fs") || err.contains("net,fs"), "names the requested caps: {err}");
    assert!(
        store::load_fleet().find("overreach").is_none(),
        "the denied spawn is not in the ledger"
    );
}

#[test]
fn non_attenuating_delegate_is_rejected_by_a0n_auth() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("delspawn-nonatten");

    let parent = Keypair::generate();
    let child = Keypair::generate();

    // root -> parent attenuated to caps=[net]; the parent then tries to delegate a
    // SUPERSET (caps=[net,fs]) to a child — a0n-auth must reject the mint.
    let parent_token = root_spawn_ucan(parent.did(), Some(&["net"]));
    let err = match ops::delegate_spawn(DelegateSpawnRequest {
        parent_ucan: parent_token,
        issuer_secret_hex: parent.secret_hex(),
        to_did: child.did().to_string(),
        caps: vec!["net".into(), "fs".into()],
        ttl_secs: 1800,
    }) {
        Ok(_) => panic!("a non-attenuating delegate must be rejected"),
        Err(e) => e,
    };
    assert!(err.contains("delegate-spawn"), "surfaced as a delegate-spawn error: {err}");
    assert!(
        err.contains("not granted by parent") || err.to_lowercase().contains("attenuation"),
        "a0n-auth attenuation rejection: {err}"
    );
}

#[test]
fn unrestricted_root_spawn_keeps_todays_behavior() {
    let _env = ENV_GUARD.lock().unwrap_or_else(|e| e.into_inner());
    let _home = Home::new("delspawn-root");

    // A root holder (no constraints.caps) can spawn any valid caps — unchanged.
    let root = store::ensure_root().expect("root");
    let ucan = root_spawn_ucan(root.did(), None);
    ops::spawn(spawn_req(&ucan, "rooty", &["net", "fs", "exec"]))
        .expect("an unrestricted root spawn admits any caps");
    let rec = store::load_fleet().find("rooty").expect("ledger").clone();
    assert_eq!(rec.depth, 1, "a root-issued spawn is depth 1");
    assert_eq!(rec.caps.len(), 3);
}
